-- ============================================================
-- SCALABLE SUMMIT CRM — Supabase Schema
-- Run this entire file in Supabase > SQL Editor > New Query
-- ============================================================

-- 1. POSTS TABLE
create table if not exists public.posts (
  id            serial primary key,
  first_name    text not null,
  last_name     text,
  title         text,
  company       text,
  post_link     text,
  summary       text,
  tagged        text,
  reactions     integer default 0,
  comments      integer default 0,
  reposts       integer default 0,
  user_email    text,          -- email of the person who "owns" this row
  user_id       uuid,          -- linked to auth.users once they register
  created_at    timestamptz default now(),
  updated_at    timestamptz default now()
);

-- 2. ROW LEVEL SECURITY
alter table public.posts enable row level security;

-- Admin can do everything (set your email below)
create policy "Admin full access" on public.posts
  for all
  using (auth.jwt() ->> 'email' = 'YOUR_ADMIN_EMAIL@EMAIL.COM')
  with check (auth.jwt() ->> 'email' = 'YOUR_ADMIN_EMAIL@EMAIL.COM');

-- Users can read their own row
create policy "Users read own row" on public.posts
  for select
  using (auth.jwt() ->> 'email' = user_email);

-- Users can update their own row
create policy "Users update own row" on public.posts
  for update
  using (auth.jwt() ->> 'email' = user_email)
  with check (auth.jwt() ->> 'email' = user_email);

-- 3. AUTO-UPDATE updated_at
create or replace function public.handle_updated_at()
returns trigger as $$
begin
  new.updated_at = now();
  return new;
end;
$$ language plpgsql;

create trigger on_post_updated
  before update on public.posts
  for each row execute procedure public.handle_updated_at();

-- 4. SEED DATA — all 56 posts
